widgets.onValue:
if(get('Toggle_M')=="Off"){
  set('Toggle_M',"On");
  set('6_5_2',"AUTO");
  set('6_5_1',"●");
  set('2_0',"Auto Pitch On")
  setTimeout(()=>{
    set('2_0',"");
  },500)
} else if(get('Toggle_M')=="On"){
  set('Toggle_M',"Off");
  set('6_5_2',"");
  set('6_5_1',"");
  set('2_0',"Auto Pitch Off")
  setTimeout(()=>{
    set('2_0',"");
  },500)
}

